              const t = setInterval(() => setTime(prev => {
                    let { h, m, s } = prev; s--;
                          if (s < 0) { s = 59; m--; } if (m < 0) { m = 59; h--; } if (h < 0) { h = 23; m = 59; s = 59; }
                                return { h, m, s };
                                    }), 1000);
